import { z } from "zod";

export const calculateCostSchema = z.object({
  originCountry: z.string().length(2),
  destinationCountry: z.string().length(2),
  weightKg: z.number().positive().max(1000),
  transportType: z.enum(["air", "rail", "sea", "combined"]).optional(),
});

export const createRouteSchema = z.object({
  originCountry: z.string().length(2),
  destinationCountry: z.string().length(2),
  transportType: z.enum(["air", "rail", "sea", "combined"]),
  ratePerKg: z.number().positive(),
  minDays: z.number().int().positive(),
  maxDays: z.number().int().positive(),
  isActive: z.boolean().default(true),
});

export const updateRouteSchema = createRouteSchema.partial();

export type CalculateCostInput = z.infer<typeof calculateCostSchema>;
export type CreateRouteInput = z.infer<typeof createRouteSchema>;
export type UpdateRouteInput = z.infer<typeof updateRouteSchema>;
